module RefModule(
    input  clock,
    input  reset,
    input  [4:0]  ReadReg1, ReadReg2, WriteReg,
    input  [31:0] WriteData,
    input  RegWrite,
    output [31:0] ReadData1, ReadData2
    );
    reg [31:0] unused_registers [1:31];
    integer i;
    initial begin
        for (i=1; i<32; i=i+1) begin
            unused_registers[i] <= 0;
        end
    end
    always @(posedge clock) begin
        if (reset) begin
            for (i=1; i<32; i=i+1) begin
                unused_registers[i] <= 0;
            end
        end
        else begin
            if (WriteReg != 0)
                unused_registers[WriteReg] <= (RegWrite) ? WriteData : unused_registers[WriteReg];
        end
    end
    assign ReadData1 = (ReadReg1 == 0) ? 32'h00000000 : unused_registers[ReadReg1];
    assign ReadData2 = (ReadReg2 == 0) ? 32'h00000000 : unused_registers[ReadReg2];
endmodule
